sys_ui_action.script:
if (!g_form.getValue('github_repo_url')) {
    g_form.addErrorMessage('Please enter a GitHub repository URL first');
    return;
}

g_form.addInfoMessage('Validating repository access...');

var ga = new GlideAjax('GitHubValidationAjax');
ga.addParam('sysparm_name', 'validateRepository');
ga.addParam('sysparm_repo_url', g_form.getValue('github_repo_url'));
ga.addParam('sysparm_branch', g_form.getValue('github_branch') || 'main');
ga.getXML(function(response) {
    var result = response.responseXML.documentElement.getAttribute("answer");
    try {
        var data = JSON.parse(result);
        if (data.success) {
            g_form.addInfoMessage('✓ Repository validation successful: ' + data.message);
            if (data.suggested_scope && !g_form.getValue('application_scope')) {
                g_form.setValue('application_scope', data.suggested_scope);
                g_form.addInfoMessage('Suggested application scope populated');
            }
        } else {
            g_form.addErrorMessage('✗ Repository validation failed: ' + data.error);
        }
    } catch (e) {
        g_form.addErrorMessage('Error validating repository: ' + e.message);
    }
});
